type AppProxy struct {
	devportal.UnimplementedAppServer
	client devportal.AppClient
}

func init() {
	proxyutil.Register(&devportal.App_ServiceDesc, NewAppProxy)
}
func NewAppProxy(cc grpc.ClientConnInterface) devportal.AppServer {
	return &AppProxy{client: devportal.NewAppClient(cc)}
}
func (p *AppProxy) Create(ctx context.Context, in *app.AppCreationRequest) (*info.AppInfo, error) {
	return proxyutil.ProxyMethod[app.AppCreationRequest, info.AppInfo](p.client.Create)(ctx, in)
}
func (p *AppProxy) Search(ctx context.Context, in *app.AppSearchRequest) (*app.AppSearchResponse, error) {
	return proxyutil.ProxyMethod[app.AppSearchRequest, app.AppSearchResponse](p.client.Search)(ctx, in)
}
